class Solution:
    def findPairs(self, nums, k):
        n = len(nums)
        found = set()
        for i in range(n):
            for j in range(i + 1, n):
                if abs(nums[i] - nums[j]) == k:
                    found.add((min(nums[i], nums[j]), max(nums[i], nums[j])))
        return len(found)

