var findPairs = function(nums, k) {
    const c = new Map();
    for (const v of nums) c.set(v, (c.get(v) || 0) + 1);
    let res = 0;
    if (k === 0) {
        for (const v of c.values()) if (v >= 2) res++;
        return res;
    }
    for (const x of c.keys()) if (c.has(x + k)) res++;
    return res;
};
